final:
module RefModule (  
    input [15:0] A,  
    input [15:0] B,  
    input sel,  
    output reg [15:0] Y  
);  
  wire [15:0] _tap_A = A & {16{1'b1}};

always @(*) begin  
    case(sel)  
        1'b0: Y = A;  
        1'b1: Y = B;  
        default: Y = 16'b0;  
    endcase  
end  
endmodule
